(function () {
  const state = {
    count: '4',
    icons: true,
    hotkeys: true,
    dividers: true,
    header: false,
    danger: true,
    disabled: false,
    submenu: false
  };
  const controls = document.getElementById('pg-controls');
  const stage = document.getElementById('pg-stage');
  const codeEl = document.getElementById('pg-code');
  let anchor,
    trigger,
    menu,
    open = true;
  function ctlSelect(label, options, key) {
    const wrap = document.createElement('div');
    wrap.className = 'ctl';
    const l = document.createElement('div');
    l.className = 'lbl';
    l.textContent = label;
    wrap.appendChild(l);
    const box = document.createElement('div');
    box.className = 'pg-select';
    const sel = document.createElement('select');
    options.forEach(([v, t]) => {
      const op = document.createElement('option');
      op.value = v;
      op.textContent = t;
      if (v === state[key]) op.selected = true;
      sel.appendChild(op);
    });
    sel.addEventListener('change', () => {
      state[key] = sel.value;
      render();
    });
    box.appendChild(sel);
    wrap.appendChild(box);
    return wrap;
  }
  function ctlToggle(label, key) {
    const wrap = document.createElement('div');
    wrap.className = 'ctl';
    const b = document.createElement('button');
    b.type = 'button';
    b.className = 'toggle';
    b.setAttribute('aria-pressed', String(state[key]));
    b.innerHTML = '<span class="sw-mini"></span><span>' + label + '</span>';
    b.addEventListener('click', () => {
      state[key] = !state[key];
      b.setAttribute('aria-pressed', String(state[key]));
      render();
    });
    wrap.appendChild(b);
    return wrap;
  }
  controls.appendChild(ctlSelect('Количество пунктов', [['2', '2'], ['4', '4'], ['5', '5'], ['6', '6']], 'count'));
  controls.appendChild(ctlToggle('Иконки', 'icons'));
  controls.appendChild(ctlToggle('Горячие клавиши', 'hotkeys'));
  controls.appendChild(ctlToggle('Разделители', 'dividers'));
  controls.appendChild(ctlToggle('Заголовок группы', 'header'));
  controls.appendChild(ctlToggle('Деструктивный пункт', 'danger'));
  controls.appendChild(ctlToggle('Отключённый пункт', 'disabled'));
  controls.appendChild(ctlToggle('Подменю', 'submenu'));
  const POOL = [{
    label: 'Изменить',
    icon: 'edit'
  }, {
    label: 'Копировать',
    icon: 'copy',
    hint: '⌘C'
  }, {
    label: 'Скачать отчёт',
    icon: 'download'
  }, {
    label: 'В инструмент',
    icon: 'link-external'
  }, {
    label: 'Разделить',
    icon: 'swap-currency'
  }, {
    label: 'Погасить',
    icon: 'refresh'
  }];
  function buildSpecs() {
    const n = parseInt(state.count, 10);
    const specs = [];
    if (state.header) specs.push({
      label: 'Действия',
      header: true
    });
    for (let i = 0; i < n; i++) {
      const base = POOL[i % POOL.length];
      const s = {
        label: base.label
      };
      if (state.icons) s.icon = base.icon;
      if (base.hint && state.hotkeys) s.hint = base.hint;
      if (state.disabled && i === 1) {
        s.disabled = true;
        s.label = base.label;
      }
      specs.push(s);
    }
    if (state.submenu) {
      specs.push({
        label: 'Экспорт',
        icon: state.icons ? 'file' : null,
        sub: true
      });
    }
    if (state.danger) {
      if (state.dividers) specs.push({
        divider: true
      });
      specs.push({
        label: 'Удалить',
        icon: state.icons ? 'trash' : null,
        danger: true
      });
    }
    return specs;
  }
  function render() {
    if (menu) menu.remove();
    if (anchor) anchor.remove();
    anchor = document.createElement('span');
    anchor.className = 'menu-anchor';
    trigger = document.createElement('button');
    trigger.type = 'button';
    trigger.className = 'kebab';
    trigger.innerHTML = KEBAB;
    trigger.setAttribute('aria-label', 'Действия');
    trigger.setAttribute('aria-haspopup', 'menu');
    anchor.appendChild(trigger);
    stage.appendChild(anchor);
    menu = makeMenu(buildSpecs(), {
      floating: true
    });
    anchor.appendChild(menu);
    place();
    if (open) {
      menu.classList.add('is-open');
      trigger.setAttribute('aria-expanded', 'true');
    }
    trigger.addEventListener('click', () => {
      open = !open;
      menu.classList.toggle('is-open', open);
      trigger.setAttribute('aria-expanded', String(open));
      if (open) place();
    });

    // code
    codeEl.innerHTML = '<code>&lt;div class="menu" role="menu"&gt;…&lt;/div&gt;</code>';
  }
  function place() {
    autoPlaceMenu(anchor, menu, trigger, 'bottom', 'start', 6);
  }
  render();
  window.addEventListener('resize', () => {
    if (menu) place();
  });
  if (document.fonts && document.fonts.ready) document.fonts.ready.then(() => {
    if (menu) place();
  });
})();

