(function () {
  const root = document.getElementById('color-ref');
  if (!root) return;
  const probe = document.createElement('span');
  probe.style.cssText = 'position:absolute;left:-9999px;width:0;height:0;';
  document.body.appendChild(probe);
  function resolveHex(cssValue) {
    probe.style.backgroundColor = 'transparent';
    probe.style.backgroundColor = cssValue;
    const v = getComputedStyle(probe).backgroundColor;
    let r,
      g,
      b,
      a = 1,
      m = v.match(/color\(srgb\s+([\d.]+)\s+([\d.]+)\s+([\d.]+)(?:\s*\/\s*([\d.]+))?\)/i);
    if (m) {
      r = +m[1] * 255;
      g = +m[2] * 255;
      b = +m[3] * 255;
      if (m[4] !== undefined) a = +m[4];
    } else {
      const n = v.match(/[\d.]+/g);
      if (!n) return cssValue;
      r = +n[0];
      g = +n[1];
      b = +n[2];
      if (n[3] !== undefined) a = +n[3];
    }
    const hx = n => Math.round(n).toString(16).padStart(2, '0').toUpperCase();
    let s = '#' + hx(r) + hx(g) + hx(b);
    if (a < 1) s += ' · ' + Math.round(a * 100) + '%';
    return s;
  }
  const groups = [{
    name: 'Контейнер',
    rows: [['Фон меню', '--bg-popup'], ['Граница', '--border-light'], ['Разделитель', '--border-light']]
  }, {
    name: 'Пункт',
    rows: [['Текст', '--text-primary'], ['Иконка', '--text-secondary'], ['Горячая клавиша', '--text-inactive'], ['Фон · hover / focus', '--tertiary']]
  }, {
    name: 'Деструктивный',
    rows: [['Текст', '--error-dark'], ['Иконка', '--error'], ['Фон · hover', '--error-bg-light']]
  }, {
    name: 'Служебное',
    rows: [['Выбранный · галочка', '--primary'], ['Отключённый · текст', '--text-inactive'], ['Заголовок группы', '--text-inactive']]
  }];
  root.innerHTML = groups.map(g => `
    <section class="cref-group">
      <h3>${g.name}</h3>
      <div class="cref-rows">
        ${g.rows.map(([role, tok]) => `
          <div class="cref-row">
            <div class="cref-sw"><div class="cf" style="background:var(${tok});"></div></div>
            <div class="cref-meta"><p class="role">${role}</p><p class="tname">${tok}</p></div>
            <div class="cref-hex">${resolveHex('var(' + tok + ')')}</div>
          </div>`).join('')}
      </div>
    </section>`).join('');
  probe.remove();
})();

