  if (label != null && orientation === 'h' && variant !== 'section') {
    const c = ['dvd-text', 'dvd-text--' + align];
    if (strong) c.push('dvd-text--strong');
    if (dashed) c.push('dvd-text--dashed');
    return c.join(' ');
  }
  const c = ['dvd', 'dvd--' + orientation];
