  /* ============================ STATES (spec tables) ============================ */
  (function () {
    const probe = document.createElement('span');
    probe.style.cssText = 'position:absolute;left:-9999px;width:0;height:0;';
    document.body.appendChild(probe);
    function resolveHex(token) {
      probe.style.backgroundColor = 'transparent';
      probe.style.backgroundColor = 'var(' + token + ')';
      const v = getComputedStyle(probe).backgroundColor;
      let r,
        g,
        b,
        a = 1,
        m = v.match(/color\(srgb\s+([\d.]+)\s+([\d.]+)\s+([\d.]+)(?:\s*\/\s*([\d.]+))?\)/i);
      if (m) {
        r = +m[1] * 255;
        g = +m[2] * 255;
        b = +m[3] * 255;
        if (m[4] !== undefined) a = +m[4];
      } else {
        const n = v.match(/[\d.]+/g);
        if (!n) return '';
        r = +n[0];
        g = +n[1];
        b = +n[2];
        if (n[3] !== undefined) a = +n[3];
      }
      const hx = n => Math.round(n).toString(16).padStart(2, '0').toUpperCase();
      let s = '#' + hx(r) + hx(g) + hx(b);
      if (a < 1) s += ', ' + Math.round(a * 100) + '%';
      return s;
    }
    function cline(role, token, name, raw) {
      return `<div class="spec__cline"><b>${role}</b><span class="spec__sw" style="background:var(${token})"></span><span><span class="tnm">${name}</span></span><span class="raw">${raw} · ${resolveHex(token)}</span></div>`;
    }
    const unselected = [['Default', {
      label: 'Text',
      badge: 3,
      state: 'default'
    }, [['Текст', '--text-secondary', 'Text_Secondary', 'CGrey_500'], ['Иконка', '--text-secondary', 'Text_Secondary', 'CGrey_500'], ['Бейдж', '--st-system-midlight', 'StSystem_MidLight', 'Swamp_400, 32%']]], ['Hover = Focus', {
      label: 'Text',
      badge: 3,
      state: 'hover'
    }, [['Fill', '--primary-bg', 'Active_PrimaryBG', 'Emerald_500, 6%'], ['Текст', '--text-primary', 'Text_Primary', 'CGrey_600'], ['Иконка', '--text-primary', 'Text_Primary', 'CGrey_600']]]];
    const selected = [['Default', {
      label: 'Text',
      badge: 3,
      state: 'selected'
    }, [['Индикатор', '--primary', 'Primary', 'Emerald_500'], ['Текст', '--text-primary', 'Text_Primary', 'CGrey_600'], ['Иконка', '--primary', 'Primary', 'Emerald_500']]], ['Hover = Focus', {
      label: 'Text',
      badge: 77,
      state: 'selected',
      _hover: true
    }, [['Fill', '--primary-bg', 'Active_PrimaryBG', 'Emerald_500, 6%'], ['Индикатор', '--primary', 'Primary', 'Emerald_500'], ['Текст', '--text-primary', 'Text_Primary', 'CGrey_600'], ['Бейдж', '--st-system-midlight', 'StSystem_MidLight', 'без изменений']]]];
    const disabledRow = [['Disabled', {
      label: 'Text',
      badge: 3,
      state: 'default',
      disabled: true
    }, [['Текст', '--st-disabled-dark', 'StDisabled_Dark', 'CGrey_600, 40%'], ['Иконка', '--st-disabled', 'StDisabled', 'CGrey_600, 24%'], ['Бейдж', '--st-disabled-midlight', 'StDisabled_MidLight', 'CGrey_600, 8%']]]];
    function buildSpec(title, states) {
      const spec = document.createElement('div');
      spec.className = 'spec';
      const head = document.createElement('div');
      head.className = 'spec__head';
      head.textContent = title;
      spec.appendChild(head);
      states.forEach(([st, opt, colors]) => {
        const row = document.createElement('div');
        row.className = 'spec__row';
        const a = document.createElement('div');
        a.className = 'spec__state';
        a.textContent = st;
        row.appendChild(a);
        const b = document.createElement('div');
        b.className = 'spec__sample';
        const grp = document.createElement('div');
        grp.className = 'tabs tabs--horiz';
        const tab = makeTab(Object.assign({
          orient: 'horiz',
          size: 'm',
          standalone: false
        }, opt));
        if (opt._hover) tab.classList.add('is-hover');
        grp.appendChild(tab);
        b.appendChild(grp);
        row.appendChild(b);
        const c = document.createElement('div');
        c.className = 'spec__colors';
        c.innerHTML = colors.map(cc => cline(cc[0], cc[1], cc[2], cc[3])).join('');
        row.appendChild(c);
        spec.appendChild(row);
      });
      return spec;
    }
    const host = document.getElementById('state-specs');
    host.appendChild(buildSpec('Unselected', unselected));
    host.appendChild(buildSpec('Selected', selected));
    host.appendChild(buildSpec('Disabled', disabledRow));
    probe.remove();
  })();

