  /* ============================ STATES / TONES (spec) ============================ */
  (function () {
    const host = document.getElementById('state-specs');
    if (!host) return;
    const probe = document.createElement('span');
    probe.style.cssText = 'position:absolute;left:-9999px;width:0;height:0;';
    document.body.appendChild(probe);
    function resolveHex(token) {
      const cssVal = token.startsWith('--') ? 'var(' + token + ')' : token;
      probe.style.backgroundColor = 'transparent';
      probe.style.backgroundColor = cssVal;
      const v = getComputedStyle(probe).backgroundColor;
      let r,
        g,
        b,
        a = 1,
        m = v.match(/color\(srgb\s+([\d.]+)\s+([\d.]+)\s+([\d.]+)(?:\s*\/\s*([\d.]+))?\)/i);
      if (m) {
        r = +m[1] * 255;
        g = +m[2] * 255;
        b = +m[3] * 255;
        if (m[4] !== undefined) a = +m[4];
      } else {
        const n = v.match(/[\d.]+/g);
        if (!n) return '';
        r = +n[0];
        g = +n[1];
        b = +n[2];
        if (n[3] !== undefined) a = +n[3];
      }
      const hx = n => Math.round(n).toString(16).padStart(2, '0').toUpperCase();
      let s = '#' + hx(r) + hx(g) + hx(b);
      if (a < 1) s += ', ' + Math.round(a * 100) + '%';
      return s;
    }
    function cline(role, token, name) {
      const cssVal = token.startsWith('--') ? 'var(' + token + ')' : token;
      return `<div class="spec__cline"><b>${role}</b><span class="spec__sw" style="background:${cssVal}"></span><span><span class="tnm">${name}</span> · ${resolveHex(token)}</span></div>`;
    }
    const rows = [['Neutral', 'Индикация запуска процесса, без окраски результата.', () => makeToast({
      kind: 'bar',
      tone: 'neutral',
      lead: 'none',
      message: 'Процесс запущен'
    }), [['Фон пилюли', '--st-grey', 'StGrey · CGrey_700'], ['Текст', '--text-on-dark', 'Text_OnDark']]], ['Loading', 'Процесс идёт — спиннер вращается 0.7 с.', () => makeToast({
      kind: 'loader',
      tone: 'neutral',
      lead: 'spinner',
      message: 'Выполняется маршрутизация'
    }), [['Фон пилюли', '--st-grey', 'StGrey · CGrey_700'], ['Спиннер', '--text-on-dark', 'Text_OnDark (currentColor)']]], ['Success', 'Процесс завершён успешно — галочка.', () => makeToast({
      kind: 'bar',
      tone: 'success',
      lead: 'icon',
      message: 'Маршрутизация завершена'
    }), [['Иконка', '--success-light', 'Success_Light'], ['Текст', '--text-on-dark', 'Text_OnDark']]], ['Error', 'Процесс завершился неуспешно — знак ошибки.', () => makeToast({
      kind: 'bar',
      tone: 'error',
      lead: 'icon',
      message: 'Не удалось запустить процесс'
    }), [['Иконка', '--error-light', 'Error_Light'], ['Текст', '--text-on-dark', 'Text_OnDark']]], ['Info', 'Нейтральное уточнение о процессе.', () => makeToast({
      kind: 'bar',
      tone: 'info',
      lead: 'icon',
      message: 'Запущена маршрутизация'
    }), [['Иконка', '--info-light', 'Info_Light'], ['Текст', '--text-on-dark', 'Text_OnDark']]]];
    rows.forEach(([title, sub, mkr, colors]) => {
      const spec = document.createElement('div');
      spec.className = 'spec';
      const row = document.createElement('div');
      row.className = 'spec__row';
      const a = document.createElement('div');
      a.className = 'spec__state';
      a.innerHTML = title + '<small>' + sub + '</small>';
      row.appendChild(a);
      const b = document.createElement('div');
      b.className = 'spec__sample';
      b.appendChild(mkr());
      row.appendChild(b);
      const c = document.createElement('div');
      c.className = 'spec__colors';
      c.innerHTML = colors.map(cc => cline(cc[0], cc[1], cc[2])).join('');
      row.appendChild(c);
      spec.appendChild(row);
      host.appendChild(spec);
    });
    probe.remove();
  })();

  /* ============================ TRANSITION Loading → Success ============================ */
  (function () {
    const host = document.getElementById('transition-demo');
    const btn = document.getElementById('transition-replay');
    if (!host) return;
    let node = null;
    function build() {
      host.innerHTML = '';
      node = makeToast({
        kind: 'loader',
        tone: 'neutral',
        lead: 'spinner',
        message: 'Выполняется маршрутизация'
      });
      host.appendChild(node);
    }
    function play() {
      build();
      setTimeout(() => {
        // спиннер → галочка, тон success
        node.classList.add('toast--success');
        const slot = node.querySelector('.toast__lead');
        slot.innerHTML = '';
        const ic = document.createElement('span');
        ic.className = 'toast__icon';
        ic.setAttribute('aria-hidden', 'true');
        ic.innerHTML = icon('check-circle');
        slot.appendChild(ic);
        node.querySelector('.toast__msg').textContent = 'Маршрутизация завершена';
        node.setAttribute('role', 'status');
        // держим ~1с и уходим фейдом вниз
        setTimeout(() => {
          node.classList.add('toast--leave');
          node.addEventListener('animationend', function onLeave() {
            node.removeEventListener('animationend', onLeave);
            node.style.visibility = 'hidden';
          });
        }, 1000);
      }, 1600);
    }
    build();
    if (btn) btn.addEventListener('click', play);
  })();

